var swiper=new Swiper(".mySwiper",{pagination:{el:".swiper-pagination",type:"progressbar"},navigation:{nextEl:".swiper-button-next",prevEl:".swiper-button-prev"},on:{init:function(){updateSliderCounter(this)},slideChange:function(){updateSliderCounter(this)}},breakpoints:{768:{slidesPerView:2,spaceBetween:20},1280:{slidesPerView:4,spaceBetween:20}}});function updateSliderCounter(e){const t=document.getElementById("current-slide"),n=document.getElementById("total-slides");if(t&&n){t.textContent=e.realIndex+1;const i=e.slides.filter(e=>!e.classList.contains("swiper-slide-duplicate")).length;n.textContent=i}}document.addEventListener("DOMContentLoaded",()=>{const e=document.querySelectorAll(".btn-menu"),t=document.querySelector(".menu");if(t&&e.length>0){e.forEach(n=>{n.addEventListener("click",n=>{n.preventDefault(),t.classList.toggle("active"),e.forEach(e=>e.classList.toggle("active"))})});t.querySelectorAll("a").forEach(n=>{n.addEventListener("click",()=>{t.classList.remove("active"),e.forEach(e=>e.classList.remove("active"))})})}}),document.addEventListener("DOMContentLoaded",()=>{const e=document.querySelectorAll(".parallax");function t(){const t=window.scrollY;window.innerWidth>=768?e.forEach(e=>{const n=parseFloat(e.getAttribute("data-speed"))||.1,i=t*n;window.requestAnimationFrame(()=>{e.style.transform=`translateY(${i}px)`})}):e.forEach(e=>{window.requestAnimationFrame(()=>{e.style.transform="translateY(0px)"})})}window.addEventListener("scroll",t),window.addEventListener("resize",t)});const THEME_KEY="preferredTheme",toggleBtn=document.getElementById("theme-switcher"),html=document.documentElement;function applyTheme(e){"dark"===e?html.setAttribute("data-theme","dark"):html.removeAttribute("data-theme"),localStorage.setItem(THEME_KEY,e)}function initTheme(){const e=localStorage.getItem(THEME_KEY);if(e)applyTheme(e);else{applyTheme(window.matchMedia("(prefers-color-scheme: dark)").matches?"dark":"light")}}toggleBtn.addEventListener("click",()=>{applyTheme("dark"===html.getAttribute("data-theme")?"light":"dark")}),initTheme();